+/// Inference Profiler - pprof-style profiler for LLM inference
+///
+/// Based on Go's runtime/pprof pattern:
+/// - Samples execution phases at intervals
+/// - Accumulates timing data
+/// - Shows phase breakdown
+///
+/// IMPORTANT: Bottleneck detection uses hardcoded heuristics tuned for Apple Silicon.
+/// These thresholds may not apply to other hardware (NVIDIA GPUs, AMD, CPU-only, etc.)
+///
+/// TODO: Implement adaptive baseline profiling:
+/// 1. On first run, benchmark hardware to establish baseline phase percentages
+/// 2. Store baseline in ~/.cache/zell/hardware_profile.json
+/// 3. Compare current run vs baseline to detect performance regressions
+/// 4. Flag anomalies (e.g., "CRUNCH 20% slower than baseline")
+///
+/// Usage:
+///   var profiler = InferenceProfiler.init();
+///   profiler.start();
+///   // ... run inference ...
+///   profiler.sample(.gather, elapsed_ns);
+///   profiler.sample(.crunch, elapsed_ns);
+///   // ...
+///   profiler.printReport();
+///
+const std = @import("std");
+
+pub const Phase = enum {
+    gather,    // Batch assembly
+    crunch,    // GPU decode (llama_decode)
+    dispatch,  // Sampling + callbacks
+    speculation, // Draft model speculation
+};
+
+pub const Bottleneck = enum {
+    gpu_memory,    // CRUNCH > 80% → partial GPU offload
+    cpu_overhead,  // GATHER+DISPATCH > 30% → scheduler overhead
+    speculation,   // SPECULATION > 40% → draft model too slow
+    balanced,      // No clear bottleneck
+};
+
+pub const InferenceProfiler = struct {
+    phase_totals: [4]u64 = .{0} ** 4,
+    total_ns: u64 = 0,
+    sample_count: u64 = 0,
+    start_time: i128 = 0,
+
+    pub fn init() InferenceProfiler {
+        return InferenceProfiler{};
+    }
+
+    pub fn deinit(self: *InferenceProfiler) void {
+        _ = self;
+    }
+
+    pub fn start(self: *InferenceProfiler) void {
+        self.start_time = std.time.nanoTimestamp();
+    }
+
+    pub fn sample(self: *InferenceProfiler, phase: Phase, duration_ns: u64) void {
+        const phase_idx = @intFromEnum(phase);
+        self.phase_totals[phase_idx] += duration_ns;
+        self.total_ns += duration_ns;
+        self.sample_count += 1;
+    }
+
+    pub fn detectBottleneck(self: *const InferenceProfiler) Bottleneck {
+        if (self.total_ns == 0) return .balanced;
+
+        const crunch_pct = @as(f64, @floatFromInt(self.phase_totals[@intFromEnum(Phase.crunch)])) /
+                           @as(f64, @floatFromInt(self.total_ns));
+        const gather_dispatch_pct = (@as(f64, @floatFromInt(self.phase_totals[@intFromEnum(Phase.gather)])) +
+                                      @as(f64, @floatFromInt(self.phase_totals[@intFromEnum(Phase.dispatch)]))) /
+                                     @as(f64, @floatFromInt(self.total_ns));
+        const spec_pct = @as(f64, @floatFromInt(self.phase_totals[@intFromEnum(Phase.speculation)])) /
+                         @as(f64, @floatFromInt(self.total_ns));
+
+        // WARNING: These thresholds are heuristics tuned for M2 Pro (16GB, ~200GB/s bandwidth)
+        // They may not apply to:
+        // - High-end GPUs (RTX 4090: CRUNCH=60% might be normal)
+        // - CPU-only systems (CRUNCH=95% is expected)
+        // - Multi-GPU setups (different bottleneck profile)
+        // TODO: Make thresholds adaptive based on hardware capability
+        if (crunch_pct > 0.80) return .gpu_memory;
+        if (gather_dispatch_pct > 0.30) return .cpu_overhead;
+        if (spec_pct > 0.40) return .speculation;
+        return .balanced;
+    }
+
+    pub fn printReport(self: *const InferenceProfiler) void {
+        if (self.total_ns == 0) {
+            std.debug.print("No profiling data collected\n", .{});
+            return;
+        }
+
+        const total_ms = @as(f64, @floatFromInt(self.total_ns)) / 1_000_000.0;
+        const elapsed_s = @as(f64, @floatFromInt(std.time.nanoTimestamp() - self.start_time)) / 1_000_000_000.0;
+
+        std.debug.print("\n=== Inference Profile Report ===\n", .{});
+        std.debug.print("  Samples: {} over {d:.1}s\n", .{self.sample_count, elapsed_s});
+        std.debug.print("  Total measured: {d:.1}ms\n\n", .{total_ms});
+
+        std.debug.print("  Phase Breakdown:\n", .{});
+        inline for (std.meta.fields(Phase), 0..) |field, i| {
+            const phase_ns = self.phase_totals[i];
+            const phase_ms = @as(f64, @floatFromInt(phase_ns)) / 1_000_000.0;
+            const pct = @as(f64, @floatFromInt(phase_ns)) / @as(f64, @floatFromInt(self.total_ns)) * 100.0;
+            std.debug.print("    {s:12} {d:6.1}ms ({d:5.1}%)\n", .{field.name, phase_ms, pct});
+        }
+
+        // Bottleneck detection (heuristic, may not apply to all hardware)
+        const bottleneck = self.detectBottleneck();
+        std.debug.print("\n  🔍 Bottleneck Analysis (heuristic for Apple Silicon):\n", .{});
+        switch (bottleneck) {
+            .gpu_memory => {
+                std.debug.print("    ⚠️  GPU/Memory Bound (CRUNCH dominates)\n", .{});
+                std.debug.print("        Possible causes:\n", .{});
+                std.debug.print("          1. Partial GPU offload → CPU↔GPU ping-pong\n", .{});
+                std.debug.print("          2. Memory bandwidth limit (~40-50 tok/s max on M2 Pro)\n", .{});
+                std.debug.print("        Check: Look for 'offloaded X/Y layers' in logs\n", .{});
+                std.debug.print("        If X << Y: Set n_gpu_layers=99 to offload more layers\n", .{});
+                std.debug.print("        If X ≈ Y: Already optimized, hitting memory bandwidth limit\n", .{});
+            },
+            .cpu_overhead => {
+                std.debug.print("    ⚠️  CPU Overhead (GATHER/DISPATCH high)\n", .{});
+                std.debug.print("        Root cause: Scheduler/callback/tool overhead per token\n", .{});
+                std.debug.print("        Fix: Disable adaptive mode, tools, or hippocampus\n", .{});
+            },
+            .speculation => {
+                std.debug.print("    ⚠️  Speculation Overhead (draft model slow)\n", .{});
+                std.debug.print("        Root cause: Draft model adds more latency than it saves\n", .{});
+                std.debug.print("        Fix: Use smaller draft model or disable speculation\n", .{});
+            },
+            .balanced => {
+                std.debug.print("    ✅ Balanced (no single bottleneck)\n", .{});
+            },
+        }
+        std.debug.print("\n", .{});
+    }
+};

